public void Clicked()
{
    ETG_BillOfLading   billOfLading;
    Description255     errorMsg;
    FormControl        inventtranspick = this;

    NoYes   BOlValidation =  ETG_Parameters::find().ETG_BLValidations;

    if(BOlValidation)
    {
        billOfLading = inventtranspick.formRun().dataSource(formDataSourceStr(SalesEditLines, ETG_BillOfLading)).cursor();

        if(!billOfLading.BOLDate)
            errorMsg = 'BOLDate must be filled in.';

        if(!billOfLading.BOLNo)
            errorMsg += 'BOLNo must be filled in.';

        if(errorMsg)
            throw error(errorMsg);
    }

    next clicked();
}
